import React from 'react';

const Navbar = ({ active, setActive, onGoHome }) => {
  const menuItems = ["Início", "Serviços", "Agendamentos", "Contato"];

  const handleScroll = (id) => {
    // Se o usuário clicar em Agendamentos, mudamos o estado para trocar de tela
    if (id === "Agendamentos") {
      setActive("Agendamentos");
      return;
    }

    // Para os outros, tentamos rolar a tela
    // Primeiro garantimos que estamos na tela inicial (Home)
    setActive("Início");

    // Pequeno delay para garantir que o componente carregou antes de rolar
    setTimeout(() => {
      const element = document.getElementById(id.toLowerCase());
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }, 100);
  };

  return (
    <nav className="pb-navbar">
      <div className="pb-brand" onClick={onGoHome} style={{ cursor: 'pointer' }}>
        <div className="pb-logo-wrap">
          <div className="pb-logo">
            <span className="pb-logo-text">PB</span>
          </div>
        </div>
        <div className="pb-brand-name">
          <span>Palheta</span>
          <span>Barbearia</span>
        </div>
      </div>

      <ul className="pb-nav-links">
        {menuItems.map((item) => (
          <li key={item}>
            <button
              onClick={() => handleScroll(item)}
              className={`pb-nav-link ${active === item ? "active" : ""}`}
            >
              {item}
            </button>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
